
DELETE FROM public.roles WHERE slug = 'spy';

ON CONFLICT (slug) DO UPDATE SET
  name_fr = EXCLUDED.name_fr, faction = EXCLUDED.faction, type = EXCLUDED.type,
  presence = EXCLUDED.presence, icon = EXCLUDED.icon,
  capacite_full_text = EXCLUDED.capacite_full_text, carte_app = EXCLUDED.carte_app,
  instruction_verb = EXCLUDED.instruction_verb, target_mode = EXCLUDED.target_mode,
  usage_label = EXCLUDED.usage_label, police_verdict = EXCLUDED.police_verdict,
  emergent = EXCLUDED.emergent, min_players = EXCLUDED.min_players,
  description = EXCLUDED.description, difficulte = EXCLUDED.difficulte,
  phase_activation = EXCLUDED.phase_activation;
